### Problem Description

Unexpected meta param found in filters agg's response.

Perhaps when agg is rewritten, an empty meta will be returned.

https://github.com/elastic/elasticsearch/blob/8.3/server/src/main/java/org/elasticsearch/search/aggregations/AggregationBuilder.java#L127
```java
    @Override
    public final AggregationBuilder rewrite(QueryRewriteContext context) throws IOException {
        AggregationBuilder rewritten = doRewrite(context);
        AggregatorFactories.Builder rewrittenSubAggs = factoriesBuilder.rewrite(context);
        if (rewritten != this) {
            return rewritten.setMetadata(getMetadata()).subAggregations(rewrittenSubAggs);
        } else if (rewrittenSubAggs != factoriesBuilder) {
            return shallowCopy(rewrittenSubAggs, getMetadata());
        } else {
            return this;
        }
    }
```

https://github.com/elastic/elasticsearch/blob/8.3/server/src/main/java/org/elasticsearch/search/aggregations/AbstractAggregationBuilder.java#L117
```java
    public Map<String, Object> getMetadata() {
        return metadata == null ? Collections.emptyMap() : Collections.unmodifiableMap(metadata);
    }
```


### Steps to Reproduce

```
DELETE test_1

PUT test_1
{
  "mappings": {
    "properties": {
      "int_field":{
        "type": "integer"
      }
    }
  }
}

PUT test_1/_bulk?refresh
{"index":{"_id":"1"}}
{"int_field":1}
{"index":{"_id":"2"}}
{"int_field":51}
{"index":{"_id":"3"}}
{"int_field":101}
{"index":{"_id":"4"}}
{"int_field":151}

GET test_1/_search
{
  "size": 0,
  "aggs": {
    "the_filters": {
      "filters": {
        "filters": [
          {
            "match": {
              "int_field": 101
            }
          },
          {
            "match": {
              "int_field": 151
            }
          }
        ]
      }
    }
  }
}

response:
{
    "took": 3,
    "timed_out": false,
    "_shards": {
        "total": 1,
        "successful": 1,
        "skipped": 0,
        "failed": 0
    },
    "hits": {
        "total": {
            "value": 4,
            "relation": "eq"
        },
        "max_score": null,
        "hits": []
    },
    "aggregations": {
        "the_filters": {
            "meta": {},
            "buckets": [
                {
                    "doc_count": 1
                },
                {
                    "doc_count": 1
                }
